<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Search Results for {{ query }}</title>
</head>
<body>
<div id="search-results-page">
    <h1>Search Results for "{{ query }}"</h1>

    <div id="job-results">
        <h2>Job Results</h2>
        {% if job_results %}
        <ul>
            {% for job in job_results %}
            <li id="job-{{ job.job_id }}">
                <a href="{{ url_for('job_details', job_id=job.job_id) }}">{{ job.title }}</a> - {{ job.company_name }} - {{ job.location }}
            </li>
            {% endfor %}
        </ul>
        {% else %}
        <p id="no-results-message">No job results found.</p>
        {% endif %}
    </div>

    <div id="company-results">
        <h2>Company Results</h2>
        {% if company_results %}
        <ul>
            {% for company in company_results %}
            <li id="company-{{ company.company_id }}">
                <a href="{{ url_for('company_profile', company_id=company.company_id) }}">{{ company.company_name }}</a> - {{ company.industry }}
            </li>
            {% endfor %}
        </ul>
        {% else %}
        <p id="no-results-message">No company results found.</p>
        {% endif %}
    </div>

    <button id="back-to-dashboard" onclick="window.location.href='{{ url_for('dashboard') }}'">Back to Dashboard</button>
</div>
</body>
</html>

